 1→import { createServerSupabase } from '@/lib/supabase/server';
 2→import { NextRequest, NextResponse } from 'next/server';
 3→
 4→export async function POST(request: NextRequest) {
 5→  const supabase = await createServerSupabase();
 6→
 7→  // Verify the merchant is authenticated
 8→  const { data: { user } } = await supabase.auth.getUser();
 9→  if (!user) {
10→    return NextResponse.json({ error: 'Non authentifie' }, { status: 401 });
11→  }
12→
13→  const body = await request.json();
14→  const { customer_qr_id, secret_key, program_id } = body;
15→
16→  if (!customer_qr_id || !secret_key) {
17→    return NextResponse.json({ error: 'customer_qr_id et secret_key requis' }, { status: 400 });
18→  }
19→
20→  // Validate the customer QR code
21→  const { data: qrCode } = await supabase
22→    .from('customer_qr_codes')
23→    .select('*, customers(id, email, full_name)')
24→    .eq('id', customer_qr_id)
25→    .eq('secret_key', secret_key)
26→    .eq('is_active', true)
27→    .single();
28→
29→  if (!qrCode) {
30→    return NextResponse.json({ error: 'QR code invalide ou expire' }, { status: 404 });
31→  }
32→
33→  const customerId = qrCode.customer_id;
34→
35→  // If program_id is provided, fetch the specific card
36→  if (program_id) {
37→    const { data: card } = await supabase
38→      .from('customer_cards')
39→      .select('*, loyalty_programs(name, type, target)')
40→      .eq('customer_id', customerId)
41→      .eq('program_id', program_id)
42→      .single();
43→
44→    return NextResponse.json({
45→      customer: qrCode.customers,
46→      card: card || null,
47→    });
48→  }
49→
50→  // Otherwise, fetch all cards for the merchant's programs
51→  const { data: merchantPrograms } = await supabase
52→    .from('loyalty_programs')
53→    .select('id')
54→    .eq('merchant_id', user.id);
55→
56→  const programIds = merchantPrograms?.map(p => p.id) || [];
57→
58→  const { data: cards } = await supabase
59→    .from('customer_cards')
60→    .select('*, loyalty_programs(name, type, target)')
61→    .eq('customer_id', customerId)
62→    .in('program_id', programIds.length > 0 ? programIds : ['__none__']);
63→
64→  return NextResponse.json({
65→    customer: qrCode.customers,
66→    cards: cards || [],
67→  });
68→}
