  1→import { createServerSupabase } from '@/lib/supabase/server';
  2→import { NextRequest, NextResponse } from 'next/server';
  3→
  4→export async function POST(request: NextRequest) {
  5→  const supabase = await createServerSupabase();
  6→
  7→  const { data: { user } } = await supabase.auth.getUser();
  8→  if (!user) {
  9→    return NextResponse.json({ error: 'Non authentifie' }, { status: 401 });
 10→  }
 11→
 12→  const body = await request.json();
 13→  const { card_id, amount, program_id, customer_id } = body;
 14→
 15→  if (!amount || amount <= 0) {
 16→    return NextResponse.json({ error: 'Montant invalide' }, { status: 400 });
 17→  }
 18→
 19→  // We need either card_id OR (program_id + customer_id) to identify the card
 20→  let targetCardId = card_id;
 21→
 22→  if (!targetCardId && program_id && customer_id) {
 23→    // Verify the program belongs to this merchant
 24→    const { data: program } = await supabase
 25→      .from('loyalty_programs')
 26→      .select('id')
 27→      .eq('id', program_id)
 28→      .eq('merchant_id', user.id)
 29→      .single();
 30→
 31→    if (!program) {
 32→      return NextResponse.json({ error: 'Programme non trouve' }, { status: 404 });
 33→    }
 34→
 35→    // Find or create the customer card
 36→    let { data: card } = await supabase
 37→      .from('customer_cards')
 38→      .select('id, balance')
 39→      .eq('customer_id', customer_id)
 40→      .eq('program_id', program_id)
 41→      .single();
 42→
 43→    if (!card) {
 44→      // Auto-enroll the customer
 45→      const { data: newCard, error } = await supabase
 46→        .from('customer_cards')
 47→        .insert({ customer_id, program_id, balance: 0 })
 48→        .select('id, balance')
 49→        .single();
 50→
 51→      if (error) {
 52→        return NextResponse.json({ error: error.message }, { status: 500 });
 53→      }
 54→      card = newCard;
 55→    }
 56→
 57→    targetCardId = card!.id;
 58→  }
 59→
 60→  if (!targetCardId) {
 61→    return NextResponse.json({ error: 'card_id ou (program_id + customer_id) requis' }, { status: 400 });
 62→  }
 63→
 64→  // Fetch current card
 65→  const { data: card } = await supabase
 66→    .from('customer_cards')
 67→    .select('*, loyalty_programs(merchant_id)')
 68→    .eq('id', targetCardId)
 69→    .single();
 70→
 71→  if (!card) {
 72→    return NextResponse.json({ error: 'Carte non trouvee' }, { status: 404 });
 73→  }
 74→
 75→  // Verify the merchant owns this program
 76→  if (card.loyalty_programs.merchant_id !== user.id) {
 77→    return NextResponse.json({ error: 'Acces refuse' }, { status: 403 });
 78→  }
 79→
 80→  const newBalance = card.balance + amount;
 81→
 82→  // Update balance
 83→  const { error: updateError } = await supabase
 84→    .from('customer_cards')
 85→    .update({ balance: newBalance })
 86→    .eq('id', targetCardId);
 87→
 88→  if (updateError) {
 89→    return NextResponse.json({ error: updateError.message }, { status: 500 });
 90→  }
 91→
 92→  // Log transaction
 93→  const { error: txnError } = await supabase.from('transactions').insert({
 94→    card_id: targetCardId,
 95→    merchant_id: user.id,
 96→    type: 'earn',
 97→    amount,
 98→    source: 'qr',
 99→  });
100→
101→  if (txnError) {
102→    return NextResponse.json({ error: txnError.message }, { status: 500 });
103→  }
104→
105→  return NextResponse.json({
106→    success: true,
107→    new_balance: newBalance,
108→    amount_added: amount,
109→  });
110→}
