 1→import { createServerSupabase } from '@/lib/supabase/server';
 2→import { NextRequest, NextResponse } from 'next/server';
 3→
 4→export async function POST(request: NextRequest) {
 5→  const supabase = await createServerSupabase();
 6→
 7→  const { data: { user } } = await supabase.auth.getUser();
 8→  if (!user) {
 9→    return NextResponse.json({ error: 'Non authentifie' }, { status: 401 });
10→  }
11→
12→  const body = await request.json();
13→  const { card_id, reward_id } = body;
14→
15→  if (!card_id || !reward_id) {
16→    return NextResponse.json({ error: 'card_id et reward_id requis' }, { status: 400 });
17→  }
18→
19→  // Fetch the reward
20→  const { data: reward } = await supabase
21→    .from('rewards')
22→    .select('*, loyalty_programs(merchant_id, type, target)')
23→    .eq('id', reward_id)
24→    .eq('is_active', true)
25→    .single();
26→
27→  if (!reward) {
28→    return NextResponse.json({ error: 'Recompense non trouvee ou inactive' }, { status: 404 });
29→  }
30→
31→  // Verify merchant owns this program
32→  if (reward.loyalty_programs.merchant_id !== user.id) {
33→    return NextResponse.json({ error: 'Acces refuse' }, { status: 403 });
34→  }
35→
36→  // Fetch the customer card
37→  const { data: card } = await supabase
38→    .from('customer_cards')
39→    .select('*')
40→    .eq('id', card_id)
41→    .eq('program_id', reward.program_id)
42→    .single();
43→
44→  if (!card) {
45→    return NextResponse.json({ error: 'Carte non trouvee pour ce programme' }, { status: 404 });
46→  }
47→
48→  // Check if customer has enough balance (target = cost to redeem)
49→  const cost = reward.loyalty_programs.target;
50→
51→  if (card.balance < cost) {
52→    return NextResponse.json({
53→      error: `Solde insuffisant. Requis: ${cost}, Actuel: ${card.balance}`,
54→    }, { status: 400 });
55→  }
56→
57→  // Deduct balance
58→  const newBalance = card.balance - cost;
59→  const { error: updateError } = await supabase
60→    .from('customer_cards')
61→    .update({ balance: newBalance })
62→    .eq('id', card_id);
63→
64→  if (updateError) {
65→    return NextResponse.json({ error: updateError.message }, { status: 500 });
66→  }
67→
68→  // Log redeem transaction
69→  const { error: txnError } = await supabase.from('transactions').insert({
70→    card_id,
71→    merchant_id: user.id,
72→    type: 'redeem',
73→    amount: cost,
74→    source: 'manual',
75→  });
76→
77→  if (txnError) {
78→    return NextResponse.json({ error: txnError.message }, { status: 500 });
79→  }
80→
81→  return NextResponse.json({
82→    success: true,
83→    reward_name: reward.name,
84→    cost,
85→    new_balance: newBalance,
86→  });
87→}
