 1→'use client';
 2→
 3→import { useState } from 'react';
 4→import { QRCode } from 'react-qrcode-logo';
 5→import { createClient } from '@/lib/supabase/client';
 6→import Button from '@/components/ui/Button';
 7→import Card from '@/components/ui/Card';
 8→import { toast } from 'sonner';
 9→import type { LoyaltyProgram } from '@/lib/supabase/types';
10→
11→interface QrGeneratorProps {
12→  programs: LoyaltyProgram[];
13→  merchantId: string;
14→  appUrl: string;
15→}
16→
17→export default function QrGenerator({ programs, merchantId, appUrl }: QrGeneratorProps) {
18→  const [selectedProgram, setSelectedProgram] = useState(programs[0]?.id || '');
19→  const [generatedUrl, setGeneratedUrl] = useState('');
20→  const [loading, setLoading] = useState(false);
21→
22→  const generate = async () => {
23→    if (!selectedProgram) {
24→      toast.error('Veuillez sélectionner un programme.');
25→      return;
26→    }
27→    setLoading(true);
28→    const supabase = createClient();
29→    const { data, error } = await supabase.from('merchant_qr_codes').insert({
30→      merchant_id: merchantId,
31→      program_id: selectedProgram,
32→      qr_url: `${appUrl}/scan/pending`,
33→    }).select().single();
34→
35→    if (error) { toast.error(error.message); setLoading(false); return; }
36→
37→    const url = `${appUrl}/scan/${data.id}`;
38→    await supabase.from('merchant_qr_codes').update({ qr_url: url }).eq('id', data.id);
39→    setGeneratedUrl(url);
40→    setLoading(false);
41→    toast.success('QR code généré !');
42→  };
43→
44→  if (programs.length === 0) {
45→    return (
46→      <Card className="text-center py-12">
47→        <p className="text-[var(--text-tertiary)]">Créez d&apos;abord un programme de fidélité pour générer des QR codes.</p>
48→      </Card>
49→    );
50→  }
51→
52→  return (
53→    <div className="space-y-6">
54→      <Card padding="lg" className="max-w-md">
55→        <div className="space-y-4">
56→          <div className="space-y-1.5">
57→            <label className="text-[13px] font-medium text-[var(--text-secondary)]">Programme</label>
58→            <select
59→              value={selectedProgram}
60→              onChange={e => setSelectedProgram(e.target.value)}
61→              className="w-full px-3 py-2 text-sm rounded-lg border border-[var(--border-default)] bg-[var(--bg-surface)] text-[var(--text-primary)]"
62→            >
63→              {programs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
64→            </select>
65→          </div>
66→          <Button onClick={generate} loading={loading}>Générer un QR code</Button>
67→        </div>
68→      </Card>
69→
70→      {generatedUrl && (
71→        <Card padding="lg" className="max-w-md text-center">
72→          <div className="inline-block p-4 bg-white rounded-xl">
73→            <QRCode value={generatedUrl} size={200} qrStyle="dots" eyeRadius={8} />
74→          </div>
75→          <p className="text-[12px] text-[var(--text-tertiary)] mt-3 break-all">{generatedUrl}</p>
76→        </Card>
77→      )}
78→    </div>
79→  );
80→}
