 1→'use client';
 2→
 3→import { useState } from 'react';
 4→import { useRouter } from 'next/navigation';
 5→import { createClient } from '@/lib/supabase/client';
 6→import Button from '@/components/ui/Button';
 7→import Input from '@/components/ui/Input';
 8→import Card from '@/components/ui/Card';
 9→import { toast } from 'sonner';
10→
11→export default function ProgramForm({ merchantId }: { merchantId: string }) {
12→  const router = useRouter();
13→  const [loading, setLoading] = useState(false);
14→  const [form, setForm] = useState({ name: '', type: 'stamp' as 'stamp' | 'points', target: 10, welcomeBonus: 1 });
15→
16→  const update = (key: string, value: string | number) => setForm(prev => ({ ...prev, [key]: value }));
17→
18→  const handleSubmit = async (e: React.FormEvent) => {
19→    e.preventDefault();
20→    setLoading(true);
21→    const supabase = createClient();
22→
23→    const { error } = await supabase.from('loyalty_programs').insert({
24→      merchant_id: merchantId,
25→      name: form.name,
26→      type: form.type,
27→      target: form.target,
28→      welcome_bonus: form.welcomeBonus,
29→    });
30→
31→    if (error) { toast.error(error.message); setLoading(false); return; }
32→    toast.success('Programme créé !');
33→    router.push('/merchant/programs');
34→    router.refresh();
35→  };
36→
37→  return (
38→    <Card padding="lg" className="max-w-lg">
39→      <form onSubmit={handleSubmit} className="space-y-4">
40→        <Input label="Nom du programme" value={form.name} onChange={e => update('name', e.target.value)} required placeholder="ex: Carte Café" />
41→
42→        <div className="space-y-1.5">
43→          <label className="text-[13px] font-medium text-[var(--text-secondary)]">Type</label>
44→          <div className="flex gap-3">
45→            {(['stamp', 'points'] as const).map(t => (
46→              <button key={t} type="button" onClick={() => update('type', t)}
47→                className={`flex-1 px-4 py-2 rounded-lg text-sm border transition-all ${
48→                  form.type === t
49→                    ? 'border-[var(--accent)] bg-[var(--accent-subtle)] text-[var(--accent-text)] font-medium'
50→                    : 'border-[var(--border-default)] text-[var(--text-secondary)] hover:border-[var(--border-strong)]'
51→                }`}
52→              >
53→                {t === 'stamp' ? 'Tampons' : 'Points'}
54→              </button>
55→            ))}
56→          </div>
57→        </div>
58→
59→        <Input label={form.type === 'stamp' ? 'Tampons requis' : 'Points objectif'} type="number" min={1}
60→          value={String(form.target)} onChange={e => update('target', parseInt(e.target.value) || 1)} />
61→
62→        <Input label="Bonus de bienvenue" type="number" min={0}
63→          value={String(form.welcomeBonus)} onChange={e => update('welcomeBonus', parseInt(e.target.value) || 0)} />
64→
65→        <div className="flex gap-3 pt-2">
66→          <Button type="submit" loading={loading}>Créer le programme</Button>
67→          <Button variant="ghost" onClick={() => router.back()}>Annuler</Button>
68→        </div>
69→      </form>
70→    </Card>
71→  );
72→}
