  1→'use client';
  2→
  3→import { useState } from 'react';
  4→import { createClient } from '@/lib/supabase/client';
  5→import Button from '@/components/ui/Button';
  6→import Input from '@/components/ui/Input';
  7→import Card from '@/components/ui/Card';
  8→import Badge from '@/components/ui/Badge';
  9→import { toast } from 'sonner';
 10→import { CheckCircle, Search, QrCode, Mail, Gift } from 'lucide-react';
 11→import type { LoyaltyProgram } from '@/lib/supabase/types';
 12→
 13→interface ManualScannerProps {
 14→  programs: LoyaltyProgram[];
 15→  merchantId: string;
 16→  rewards?: Array<{ id: string; name: string; program_id: string; discount_type: string; discount_value: number }>;
 17→}
 18→
 19→type SearchMode = 'email' | 'qr';
 20→
 21→export default function ManualScanner({ programs, merchantId, rewards = [] }: ManualScannerProps) {
 22→  const [mode, setMode] = useState<SearchMode>('email');
 23→  const [email, setEmail] = useState('');
 24→  const [qrInput, setQrInput] = useState('');
 25→  const [selectedProgram, setSelectedProgram] = useState(programs[0]?.id || '');
 26→  const [amount, setAmount] = useState(1);
 27→  const [loading, setLoading] = useState(false);
 28→  const [searchLoading, setSearchLoading] = useState(false);
 29→  const [foundCard, setFoundCard] = useState<any>(null);
 30→  const [redeemLoading, setRedeemLoading] = useState<string | null>(null);
 31→
 32→  const searchByEmail = async () => {
 33→    if (!email.trim()) return;
 34→    setSearchLoading(true);
 35→    setFoundCard(null);
 36→    const supabase = createClient();
 37→
 38→    const { data: customer } = await supabase
 39→      .from('customers')
 40→      .select('id, email, full_name')
 41→      .eq('email', email.trim())
 42→      .single();
 43→
 44→    if (!customer) {
 45→      toast.error('Client non trouve.');
 46→      setSearchLoading(false);
 47→      return;
 48→    }
 49→
 50→    const { data: card } = await supabase
 51→      .from('customer_cards')
 52→      .select('*, loyalty_programs(name, type, target)')
 53→      .eq('customer_id', customer.id)
 54→      .eq('program_id', selectedProgram)
 55→      .single();
 56→
 57→    if (!card) {
 58→      toast.error("Ce client n'est pas inscrit a ce programme.");
 59→      setSearchLoading(false);
 60→      return;
 61→    }
 62→
 63→    setFoundCard({ ...card, customer });
 64→    setSearchLoading(false);
 65→  };
 66→
 67→  const searchByQr = async () => {
 68→    if (!qrInput.trim()) return;
 69→    setSearchLoading(true);
 70→    setFoundCard(null);
 71→
 72→    try {
 73→      const parsed = JSON.parse(qrInput.trim());
 74→      if (parsed.type !== 'customer' || !parsed.id || !parsed.key) {
 75→        toast.error('QR code invalide.');
 76→        setSearchLoading(false);
 77→        return;
 78→      }
 79→
 80→      const res = await fetch('/api/scan/validate', {
 81→        method: 'POST',
 82→        headers: { 'Content-Type': 'application/json' },
 83→        body: JSON.stringify({
 84→          customer_qr_id: parsed.id,
 85→          secret_key: parsed.key,
 86→          program_id: selectedProgram,
 87→        }),
 88→      });
 89→
 90→      const data = await res.json();
 91→
 92→      if (!res.ok) {
 93→        toast.error(data.error || 'Erreur de validation');
 94→        setSearchLoading(false);
 95→        return;
 96→      }
 97→
 98→      if (data.card) {
 99→        setFoundCard({ ...data.card, customer: data.customer });
100→      } else {
101→        toast.error("Ce client n'est pas inscrit a ce programme.");
102→      }
103→    } catch {
104→      toast.error('Format QR invalide. Collez le contenu du QR code.');
105→    }
106→
107→    setSearchLoading(false);
108→  };
109→
110→  const addPoints = async () => {
111→    if (!foundCard) return;
112→    setLoading(true);
113→
114→    const res = await fetch('/api/scan/earn', {
115→      method: 'POST',
116→      headers: { 'Content-Type': 'application/json' },
117→      body: JSON.stringify({
118→        card_id: foundCard.id,
119→        amount,
120→      }),
121→    });
122→
123→    const data = await res.json();
124→
125→    if (!res.ok) {
126→      toast.error(data.error || 'Erreur');
127→      setLoading(false);
128→      return;
129→    }
130→
131→    const program = foundCard.loyalty_programs;
132→    toast.success(`+${amount} ${program.type === 'stamp' ? 'tampon(s)' : 'point(s)'} ajoute(s) !`);
133→    setFoundCard({ ...foundCard, balance: data.new_balance });
134→    setLoading(false);
135→  };
136→
137→  const redeemReward = async (rewardId: string) => {
138→    if (!foundCard) return;
139→    setRedeemLoading(rewardId);
140→
141→    const res = await fetch('/api/rewards/redeem', {
142→      method: 'POST',
143→      headers: { 'Content-Type': 'application/json' },
144→      body: JSON.stringify({
145→        card_id: foundCard.id,
146→        reward_id: rewardId,
147→      }),
148→    });
149→
150→    const data = await res.json();
151→
152→    if (!res.ok) {
153→      toast.error(data.error || 'Erreur');
154→      setRedeemLoading(null);
155→      return;
156→    }
157→
158→    toast.success(`Recompense "${data.reward_name}" utilisee !`);
159→    setFoundCard({ ...foundCard, balance: data.new_balance });
160→    setRedeemLoading(null);
161→  };
162→
163→  if (programs.length === 0) {
164→    return (
165→      <Card className="text-center py-12">
166→        <p className="text-[var(--text-tertiary)]">Creez d&apos;abord un programme pour utiliser le scanner.</p>
167→      </Card>
168→    );
169→  }
170→
171→  const programRewards = rewards.filter(r => r.program_id === selectedProgram);
172→
173→  return (
174→    <div className="space-y-6 max-w-lg">
175→      {/* Mode toggle */}
176→      <div className="flex gap-2">
177→        <button
178→          onClick={() => { setMode('email'); setFoundCard(null); }}
179→          className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all ${
180→            mode === 'email'
181→              ? 'bg-[var(--accent)] text-white'
182→              : 'bg-[var(--bg-surface)] border border-[var(--border-default)] text-[var(--text-secondary)]'
183→          }`}
184→        >
185→          <Mail className="w-4 h-4" /> Par email
186→        </button>
187→        <button
188→          onClick={() => { setMode('qr'); setFoundCard(null); }}
189→          className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all ${
190→            mode === 'qr'
191→              ? 'bg-[var(--accent)] text-white'
192→              : 'bg-[var(--bg-surface)] border border-[var(--border-default)] text-[var(--text-secondary)]'
193→          }`}
194→        >
195→          <QrCode className="w-4 h-4" /> Par QR code
196→        </button>
197→      </div>
198→
199→      <Card padding="lg">
200→        <h3 className="text-[15px] font-semibold text-[var(--text-primary)] mb-4">Chercher un client</h3>
201→        <div className="space-y-4">
