 1→import { NextRequest, NextResponse } from 'next/server';
 2→import Stripe from 'stripe';
 3→import { getStripe } from '@/lib/stripe';
 4→import { createServerSupabase } from '@/lib/supabase/server';
 5→
 6→export async function POST(request: NextRequest) {
 7→  const body = await request.text();
 8→  const signature = request.headers.get('stripe-signature');
 9→  const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;
10→
11→  if (!signature || !webhookSecret) {
12→    return NextResponse.json({ error: 'Missing stripe-signature or webhook secret' }, { status: 400 });
13→  }
14→
15→  let event: Stripe.Event;
16→
17→  try {
18→    const stripe = getStripe();
19→    event = stripe.webhooks.constructEvent(body, signature, webhookSecret);
20→  } catch (err: any) {
21→    console.error('Webhook signature verification failed:', err.message);
22→    return NextResponse.json({ error: 'Invalid signature' }, { status: 400 });
23→  }
24→
25→  const supabase = await createServerSupabase();
26→
27→  switch (event.type) {
28→    case 'checkout.session.completed': {
29→      const session = event.data.object as Stripe.Checkout.Session;
30→      const customerId = session.customer as string;
31→      const plan = session.metadata?.plan as 'pro' | 'business' | undefined;
32→
33→      if (customerId && plan) {
34→        await supabase
35→          .from('merchants')
36→          .update({ plan, stripe_customer_id: customerId })
37→          .eq('stripe_customer_id', customerId);
38→      }
39→      break;
40→    }
41→
42→    case 'customer.subscription.updated': {
43→      const subscription = event.data.object as Stripe.Subscription;
44→      const customerId = subscription.customer as string;
45→
46→      const priceId = subscription.items.data[0]?.price.id;
47→      let plan: 'free' | 'pro' | 'business' = 'free';
48→
49→      if (priceId === process.env.STRIPE_PRO_PRICE_ID) plan = 'pro';
50→      else if (priceId === process.env.STRIPE_BUSINESS_PRICE_ID) plan = 'business';
51→
52→      if (subscription.status === 'active') {
53→        await supabase
54→          .from('merchants')
55→          .update({ plan })
56→          .eq('stripe_customer_id', customerId);
57→      }
58→      break;
59→    }
60→
61→    case 'customer.subscription.deleted': {
62→      const subscription = event.data.object as Stripe.Subscription;
63→      const customerId = subscription.customer as string;
64→
65→      await supabase
66→        .from('merchants')
67→        .update({ plan: 'free' })
68→        .eq('stripe_customer_id', customerId);
69→      break;
70→    }
71→
72→    default:
73→      break;
74→  }
75→
76→  return NextResponse.json({ received: true });
77→}
