'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import Button from '@/components/ui/Button';
import Input from '@/components/ui/Input';
import Card from '@/components/ui/Card';
import Badge from '@/components/ui/Badge';
import { toast } from 'sonner';
import type { Merchant } from '@/lib/supabase/types';

interface MerchantSettingsProps {
  merchant: Merchant | null;
  userEmail?: string;
}

export default function MerchantSettings({ merchant, userEmail }: MerchantSettingsProps) {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [businessName, setBusinessName] = useState(merchant?.name || '');
  const [logoUrl, setLogoUrl] = useState(merchant?.logo_url || '');

  const handleSave = async () => {
    setLoading(true);
    const supabase = createClient();
    const { error } = await supabase
      .from('merchants')
      .update({ name: businessName, logo_url: logoUrl || null })
      .eq('id', merchant!.id);

    if (error) { toast.error(error.message); setLoading(false); return; }
    toast.success('Parametres sauvegardes !');
    router.refresh();
    setLoading(false);
  };

  const handleLogout = async () => {
    const supabase = createClient();
    await supabase.auth.signOut();
    router.push('/login');
  };

  return (
    <div className="space-y-6 max-w-lg">
      <Card padding="lg">
        <h3 className="text-[15px] font-semibold text-[var(--text-primary)] mb-4">Informations</h3>
        <div className="space-y-4">
          <div>
            <label className="text-[13px] font-medium text-[var(--text-secondary)]">Email</label>
            <p className="text-[13px] text-[var(--text-primary)] mt-1">{userEmail || '—'}</p>
          </div>

          <div>
            <label className="text-[13px] font-medium text-[var(--text-secondary)]">Plan</label>
            <div className="mt-1">
              <Badge variant="accent">{merchant?.plan?.toUpperCase() || 'FREE'}</Badge>
            </div>
          </div>

          <Input
            label="Nom de l'entreprise"
            value={businessName}
            onChange={e => setBusinessName(e.target.value)}
          />

          <Input
            label="URL du logo"
            value={logoUrl}
            onChange={e => setLogoUrl(e.target.value)}
            placeholder="https://..."
          />

          <Button onClick={handleSave} loading={loading}>Sauvegarder</Button>
        </div>
      </Card>

      <Card padding="lg">
        <h3 className="text-[15px] font-semibold text-[var(--text-primary)] mb-4">Compte</h3>
        <p className="text-[13px] text-[var(--text-tertiary)] mb-4">
          Membre depuis {merchant?.created_at ? new Date(merchant.created_at).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' }) : '—'}
        </p>
        <Button variant="danger" onClick={handleLogout}>Se deconnecter</Button>
      </Card>
    </div>
  );
}

