 1→import { createServerSupabase } from '@/lib/supabase/server';
 2→import { getStripe } from '@/lib/stripe';
 3→import { NextRequest, NextResponse } from 'next/server';
 4→import type Stripe from 'stripe';
 5→
 6→export async function POST(request: NextRequest) {
 7→  const supabase = await createServerSupabase();
 8→
 9→  const { data: { user } } = await supabase.auth.getUser();
10→  if (!user) {
11→    return NextResponse.json({ error: 'Non authentifie' }, { status: 401 });
12→  }
13→
14→  const body = await request.json();
15→  const { plan } = body;
16→
17→  if (!plan || !['pro', 'business'].includes(plan)) {
18→    return NextResponse.json({ error: 'Plan invalide' }, { status: 400 });
19→  }
20→
21→  const { data: merchant } = await supabase
22→    .from('merchants')
23→    .select('email, stripe_customer_id')
24→    .eq('id', user.id)
25→    .single();
26→
27→  if (!merchant) {
28→    return NextResponse.json({ error: 'Marchand non trouve' }, { status: 404 });
29→  }
30→
31→  const priceId = plan === 'pro'
32→    ? process.env.STRIPE_PRO_PRICE_ID
33→    : process.env.STRIPE_BUSINESS_PRICE_ID;
34→
35→  if (!priceId) {
36→    return NextResponse.json({ error: 'Configuration Stripe manquante' }, { status: 500 });
37→  }
38→
39→  const appUrl = process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000';
40→
41→  const sessionParams: Stripe.Checkout.SessionCreateParams = {
42→    mode: 'subscription',
43→    line_items: [{ price: priceId, quantity: 1 }],
44→    success_url: `${appUrl}/merchant/subscription?success=true`,
45→    cancel_url: `${appUrl}/merchant/subscription?canceled=true`,
46→    metadata: { plan, merchant_id: user.id },
47→  };
48→
49→  if (merchant.stripe_customer_id) {
50→    sessionParams.customer = merchant.stripe_customer_id;
51→  } else {
52→    sessionParams.customer_email = merchant.email;
53→  }
54→
55→  const stripe = getStripe();
56→  const session = await stripe.checkout.sessions.create(sessionParams);
57→
58→  return NextResponse.json({ url: session.url });
59→}
60→

