case 'checkout.session.completed': {
  const session = event.data.object as Stripe.Checkout.Session;
  const stripeCustomerId = session.customer as string;
  const plan = session.metadata?.plan as 'pro' | 'business' | undefined;
  const merchantId = session.metadata?.merchant_id;

  if (stripeCustomerId && plan) {
    // Try to update by stripe_customer_id first, then fall back to merchant_id from metadata
    const { data: updated } = await supabase
      .from('merchants')
      .update({ plan, stripe_customer_id: stripeCustomerId })
      .eq('stripe_customer_id', stripeCustomerId)
      .select('id');

    if ((!updated || updated.length === 0) && merchantId) {
      await supabase
        .from('merchants')
        .update({ plan, stripe_customer_id: stripeCustomerId })
        .eq('id', merchantId);
    }
  }
  break;
}

