24→    .eq('id', customer_qr_id)
25→    .eq('qr_secret', secret_key)
26→    .eq('is_active', true)
27→    .single();
28→
29→  if (!qrCode) {
30→    return NextResponse.json({ error: 'QR code invalide ou expire' }, { status: 404 });
31→  }
32→
33→  const customerId = qrCode.customer_id;
34→
35→  // Look up the merchant by user_id to get merchant.id
36→  const { data: merchant } = await supabase
37→    .from('merchants')
38→    .select('id')
39→    .eq('user_id', user.id)
40→    .single();
41→
42→  if (!merchant) {
43→    return NextResponse.json({ error: 'Marchand non trouve' }, { status: 404 });
