51→      .eq('customer_id', customerId)
52→      .eq('program_id', program_id)
53→      .single();
54→
55→    return NextResponse.json({
56→      customer: qrCode.customers,
57→      card: card || null,
58→    });
59→  }
60→
61→  // Otherwise, fetch all cards for the merchant's programs
62→  const { data: merchantPrograms } = await supabase
63→    .from('loyalty_programs')
