  1→import { createServerSupabase } from '@/lib/supabase/server';
  2→import { NextRequest, NextResponse } from 'next/server';
  3→
  4→export async function POST(request: NextRequest) {
  5→  const supabase = await createServerSupabase();
  6→
  7→  const { data: { user } } = await supabase.auth.getUser();
  8→  if (!user) {
  9→    return NextResponse.json({ error: 'Non authentifie' }, { status: 401 });
 10→  }
 11→
 12→  const body = await request.json();
 13→  const { card_id, amount, program_id, customer_id } = body;
 14→
 15→  if (!amount || amount <= 0) {
 16→    return NextResponse.json({ error: 'Montant invalide' }, { status: 400 });
 17→  }
 18→
 19→  // Look up the merchant by user_id to get merchant.id
 20→  const { data: merchant } = await supabase
 21→    .from('merchants')
 22→    .select('id')
 23→    .eq('user_id', user.id)
 24→    .single();
 25→
 26→  if (!merchant) {
 27→    return NextResponse.json({ error: 'Marchand non trouve' }, { status: 404 });
 28→  }
 29→
 30→  // We need either card_id OR (program_id + customer_id) to identify the card
 31→  let targetCardId = card_id;
 32→
 33→  if (!targetCardId && program_id && customer_id) {
 34→    // Verify the program belongs to this merchant
 35→    const { data: program } = await supabase
 36→      .from('loyalty_programs')
 37→      .select('id, type')
 38→      .eq('id', program_id)
 39→      .eq('merchant_id', merchant.id)
 40→      .single();
 41→
 42→    if (!program) {
 43→      return NextResponse.json({ error: 'Programme non trouve' }, { status: 404 });
 44→    }
 45→
 46→    // Find or create the customer card
 47→    let { data: card } = await supabase
 48→      .from('customer_cards')
 49→      .select('id, current_stamps, current_points')
 50→      .eq('customer_id', customer_id)
 51→      .eq('program_id', program_id)
 52→      .single();
 53→
 54→    if (!card) {
 55→      // Auto-enroll the customer
 56→      const { data: newCard, error } = await supabase
 57→        .from('customer_cards')
 58→        .insert({ customer_id, program_id, current_stamps: 0, current_points: 0 })
 59→        .select('id, current_stamps, current_points')
 60→        .single();
 61→
 62→      if (error) {
 63→        return NextResponse.json({ error: error.message }, { status: 500 });
 64→      }
 65→      card = newCard;
 66→    }
 67→
 68→    targetCardId = card!.id;
 69→  }
 70→
 71→  if (!targetCardId) {
 72→    return NextResponse.json({ error: 'card_id ou (program_id + customer_id) requis' }, { status: 400 });
 73→  }
 74→
 75→  // Fetch current card with program info
 76→  const { data: card } = await supabase
 77→    .from('customer_cards')
 78→    .select('*, loyalty_programs(merchant_id, type)')
 79→    .eq('id', targetCardId)
 80→    .single();
 81→
 82→  if (!card) {
 83→    return NextResponse.json({ error: 'Carte non trouvee' }, { status: 404 });
 84→  }
 85→
 86→  // Verify the merchant owns this program
 87→  if (card.loyalty_programs.merchant_id !== merchant.id) {
 88→    return NextResponse.json({ error: 'Acces refuse' }, { status: 403 });
 89→  }
 90→
 91→  // Determine which balance field to update based on program type
 92→  const programType = card.loyalty_programs.type;
 93→  const balanceField = programType === 'stamp' ? 'current_stamps' : 'current_points';
 94→  const currentBalance = programType === 'stamp' ? card.current_stamps : card.current_points;
 95→  const newBalance = currentBalance + amount;
 96→
 97→  // Update balance
 98→  const { error: updateError } = await supabase
 99→    .from('customer_cards')
100→    .update({ [balanceField]: newBalance })
101→    .eq('id', targetCardId);
102→
103→  if (updateError) {
104→    return NextResponse.json({ error: updateError.message }, { status: 500 });
105→  }
106→
107→  // Log transaction
108→  const { error: txnError } = await supabase.from('transactions').insert({
109→    card_id: targetCardId,
110→    validated_by: merchant.id,
111→    type: 'earn',
112→    value: amount,
113→  });
114→
115→  if (txnError) {
116→    return NextResponse.json({ error: txnError.message }, { status: 500 });
117→  }
118→
119→  return NextResponse.json({
120→    success: true,
121→    new_balance: newBalance,
122→    amount_added: amount,
123→  });
124→}
