 28→  }
 29→
 30→  // Fetch the reward with program info
 31→  const { data: reward } = await supabase
 32→    .from('rewards')
 33→    .select('*, loyalty_programs(merchant_id, type, stamp_goal, points_per_euro)')
 34→    .eq('id', reward_id)
 35→    .eq('is_active', true)
 36→    .single();
 37→
 38→  if (!reward) {
 39→    return NextResponse.json({ error: 'Recompense non trouvee ou inactive' }, { status: 404 });
 40→  }
 41→
 42→  // Verify merchant owns this program
 43→  if (reward.loyalty_programs.merchant_id !== merchant.id) {
 44→    return NextResponse.json({ error: 'Acces refuse' }, { status: 403 });
 45→  }
 46→
 47→  // Fetch the customer card
 48→  const { data: card } = await supabase
 49→    .from('customer_cards')
 50→    .select('*')
 51→    .eq('id', card_id)
 52→    .eq('program_id', reward.program_id)
 53→    .single();
 54→
 55→  if (!card) {
 56→    return NextResponse.json({ error: 'Carte non trouvee pour ce programme' }, { status: 404 });
 57→  }
 58→
 59→  // Determine cost and balance field based on program type
 60→  const programType = reward.loyalty_programs.type;
 61→  let cost: number;
 62→  let balanceField: string;
 63→  let currentBalance: number;
 64→
