 16→export default function RewardForm({ programs }: RewardFormProps) {
 17→  const router = useRouter();
 18→  const [loading, setLoading] = useState(false);
 19→  const [form, setForm] = useState({
 20→    program_id: programs[0]?.id || '',
 21→    name: '',
 22→    discount_type: 'freebie' as 'percentage' | 'fixed' | 'freebie',
 23→    discount_value: 0,
 24→    points_cost: 0,
 25→    stamps_required: 0,
