 34→
 35→    setLoading(true);
 36→    const supabase = createClient();
 37→
 38→    const selectedProg = programs.find(p => p.id === form.program_id);
 39→    const { error } = await supabase.from('rewards').insert({
 40→      program_id: form.program_id,
 41→      name: form.name,
 42→      discount_type: form.discount_type,
 43→      discount_value: form.discount_type === 'freebie' ? 0 : form.discount_value,
 44→      points_cost: selectedProg?.type === 'points' ? form.points_cost : null,
 45→      stamps_required: selectedProg?.type === 'stamp' ? form.stamps_required : null,
 46→    });
 47→
 48→    if (error) { toast.error(error.message); setLoading(false); return; }
 49→    toast.success('Récompense créée !');
