 78→        <Input label="Nom de la récompense" value={form.name} onChange={e => update('name', e.target.value)} required placeholder="ex: Café offert" />
 79→
 80→        <div className="space-y-1.5">
 81→          <label className="text-[13px] font-medium text-[var(--text-secondary)]">Type de réduction</label>
